// Replace "My Other Workflow" with the name of the workflow to trigger.
const workflowName = "My Other Workflow";

if (!actor) return;

const api = game.modules.get("custom-dnd5e").api;
const success = api.workflows.executeWorkflow(workflowName, actor);

if (!success) {
  ui.notifications.warn(`Workflow "${workflowName}" not found.`);
}
